// Validate Claude's draft against the extracted emails and normalize the result
// row the app consumes. Falls back to a safe (HTML-escaped) property-maintenance
// template if the model call failed.
const ctx = $('Prep For Claude').item.json;
let o = $json.output ?? $json.text ?? {};
if (typeof o === "string") {
  try { o = JSON.parse(o); } catch { o = {}; }
}

function esc(s) {
  return String(s == null ? "" : s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

const emails = ctx.emails || [];
let best = (o.best_email || "").toString().trim().toLowerCase();
if (!emails.includes(best)) best = ctx.best_email_fallback || "";

let subject = (o.subject || "").toString().trim().slice(0, 200);
let html = (o.html || "").toString().trim();
if (!subject) subject = "Property maintenance & trades for " + ctx.business;
if (!html) {
  const trade = (ctx.category || "your").toString().replace(/\s*services?\s*$/i, "").trim() || "your";
  html = "<p>Hi " + esc(ctx.business) + ",</p><p>APMG Services is a Melbourne-based multi-trade property maintenance partner - painting, electrical, plumbing, carpentry, grounds and property make-safe - keeping " + esc(trade) + " facilities safe, compliant and well maintained through one reliable team, with minimal disruption.</p><p><a href=\"{{link}}\">See how APMG can help &rarr;</a></p><p>&mdash; The APMG Services team</p>";
}
if (!html.includes("{{link}}")) {
  html += '<p><a href="{{link}}">See how APMG can help &rarr;</a></p>';
}

return {
  json: {
    id: ctx.lead_id,
    business: ctx.business,
    category: ctx.category,
    url: ctx.url,
    emails,
    email_source: ctx.email_source,
    best_email: best,
    subject,
    html,
  },
};
